package value

import (
	"bytes"
	"context"
	"fmt"
	"testing"
)

// identityTransformer is a simple transformer that returns data unchanged.
type identityTransformer struct{}

func (t *identityTransformer) TransformFromStorage(_ context.Context, data []byte, _ Context) ([]byte, bool, error) {
	return data, false, nil
}

func (t *identityTransformer) TransformToStorage(_ context.Context, data []byte, _ Context) ([]byte, error) {
	return data, nil
}

// errorTransformer always returns the configured error.
type errorTransformer struct {
	err error
}

func (t *errorTransformer) TransformFromStorage(_ context.Context, _ []byte, _ Context) ([]byte, bool, error) {
	return nil, false, t.err
}

func (t *errorTransformer) TransformToStorage(_ context.Context, _ []byte, _ Context) ([]byte, error) {
	return nil, t.err
}

// reversingTransformer reverses the byte slice as its transformation.
type reversingTransformer struct{}

func (t *reversingTransformer) TransformFromStorage(_ context.Context, data []byte, _ Context) ([]byte, bool, error) {
	out := make([]byte, len(data))
	for i, b := range data {
		out[len(data)-1-i] = b
	}
	return out, false, nil
}

func (t *reversingTransformer) TransformToStorage(_ context.Context, data []byte, _ Context) ([]byte, error) {
	out := make([]byte, len(data))
	for i, b := range data {
		out[len(data)-1-i] = b
	}
	return out, nil
}

// TestDefaultContextAuthenticatedData verifies that DefaultContext returns its own bytes.
func TestDefaultContextAuthenticatedData(t *testing.T) {
	cases := []struct {
		name  string
		input DefaultContext
	}{
		{"nil slice", DefaultContext(nil)},
		{"empty slice", DefaultContext([]byte{})},
		{"non-empty slice", DefaultContext([]byte("some-key:/namespaces/default/pods/mypod"))},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			got := tc.input.AuthenticatedData()
			if !bytes.Equal([]byte(tc.input), got) {
				t.Errorf("AuthenticatedData() = %v, want %v", got, []byte(tc.input))
			}
		})
	}
}

// TestTransformerRoundTrip verifies that a transformer can write and then read back the same data.
func TestTransformerRoundTrip(t *testing.T) {
	original := []byte("hello kubernetes storage")
	ctx := context.Background()
	dataCtx := DefaultContext([]byte("test-key"))

	transformer := &reversingTransformer{}

	stored, err := transformer.TransformToStorage(ctx, original, dataCtx)
	if err != nil {
		t.Fatalf("TransformToStorage failed: %v", err)
	}
	if bytes.Equal(stored, original) {
		t.Errorf("TransformToStorage should have changed the data")
	}

	recovered, stale, err := transformer.TransformFromStorage(ctx, stored, dataCtx)
	if err != nil {
		t.Fatalf("TransformFromStorage failed: %v", err)
	}
	if stale {
		t.Errorf("unexpected stale=true for fresh data")
	}
	if !bytes.Equal(recovered, original) {
		t.Errorf("round-trip mismatch: got %q, want %q", recovered, original)
	}
}

// TestPrefixTransformerTransformToStoragePrependsPrefix verifies that TransformToStorage
// prepends the first transformer's prefix to the output.
func TestPrefixTransformerTransformToStoragePrependsPrefix(t *testing.T) {
	cases := []struct {
		name   string
		prefix []byte
		input  []byte
		inner  []byte
	}{
		{"simple prefix", []byte("k8s:enc:aes:"), []byte("plaintext"), []byte("ciphertext")},
		{"empty prefix", []byte(""), []byte("data"), []byte("transformed")},
		{"colon-only prefix", []byte(":"), []byte("val"), []byte("out")},
	}

	ctx := context.Background()
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			inner := &testTransformer{to: tc.inner}
			p := NewPrefixTransformers(fmt.Errorf("no match"), PrefixTransformer{
				Prefix:      tc.prefix,
				Transformer: inner,
			})

			got, err := p.TransformToStorage(ctx, tc.input, nil)
			if err != nil {
				t.Fatalf("TransformToStorage failed: %v", err)
			}
			if !bytes.HasPrefix(got, tc.prefix) {
				t.Errorf("output %q does not start with prefix %q", got, tc.prefix)
			}
			suffix := got[len(tc.prefix):]
			if !bytes.Equal(suffix, tc.inner) {
				t.Errorf("output suffix = %q, want %q", suffix, tc.inner)
			}
		})
	}
}

// TestPrefixTransformerTransformFromStorageStripsPrefix verifies that TransformFromStorage
// strips the matched prefix before passing data to the inner transformer.
func TestPrefixTransformerTransformFromStorageStripsPrefix(t *testing.T) {
	prefix := []byte("k8s:enc:v1:")
	inner := &testTransformer{from: []byte("decrypted")}
	p := NewPrefixTransformers(fmt.Errorf("no match"), PrefixTransformer{
		Prefix:      prefix,
		Transformer: inner,
	})

	input := append([]byte{}, prefix...)
	input = append(input, []byte("rawciphertext")...)

	ctx := context.Background()
	out, stale, err := p.TransformFromStorage(ctx, input, nil)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if stale {
		t.Errorf("unexpected stale=true for first transformer")
	}
	if !bytes.Equal(out, []byte("decrypted")) {
		t.Errorf("got %q, want %q", out, "decrypted")
	}
	// The inner transformer should have received only the data after the prefix.
	if !bytes.Equal(inner.receivedFrom, []byte("rawciphertext")) {
		t.Errorf("inner transformer received %q, want %q", inner.receivedFrom, "rawciphertext")
	}
}

// TestPrefixTransformerMismatch verifies the error returned when no prefix matches.
func TestPrefixTransformerMismatch(t *testing.T) {
	sentinel := fmt.Errorf("no transformer matched")
	p := NewPrefixTransformers(sentinel,
		PrefixTransformer{Prefix: []byte("a:"), Transformer: &identityTransformer{}},
		PrefixTransformer{Prefix: []byte("b:"), Transformer: &identityTransformer{}},
	)

	ctx := context.Background()
	_, _, err := p.TransformFromStorage(ctx, []byte("c:somedata"), nil)
	if err != sentinel {
		t.Errorf("expected sentinel error, got: %v", err)
	}
}

// TestPrefixTransformerStaleDetection verifies stale semantics: data decrypted by the
// first transformer is not stale, data from any other transformer is marked stale.
func TestPrefixTransformerStaleDetection(t *testing.T) {
	cases := []struct {
		name          string
		input         string
		expectedStale bool
	}{
		{"first transformer — not stale", "first:value", false},
		{"second transformer — stale", "second:value", true},
		{"third transformer — stale", "third:value", true},
	}

	p := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("first:"), Transformer: &testTransformer{from: []byte("v1")}},
		PrefixTransformer{Prefix: []byte("second:"), Transformer: &testTransformer{from: []byte("v2")}},
		PrefixTransformer{Prefix: []byte("third:"), Transformer: &testTransformer{from: []byte("v3")}},
	)

	ctx := context.Background()
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			_, stale, err := p.TransformFromStorage(ctx, []byte(tc.input), nil)
			if err != nil {
				t.Fatalf("unexpected error: %v", err)
			}
			if stale != tc.expectedStale {
				t.Errorf("stale = %v, want %v", stale, tc.expectedStale)
			}
		})
	}
}

// TestPrefixTransformerInnerErrorPropagates verifies that an error from the inner transformer
// is returned to the caller.
func TestPrefixTransformerInnerErrorPropagates(t *testing.T) {
	innerErr := fmt.Errorf("decryption failed")
	p := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{
			Prefix:      []byte("enc:"),
			Transformer: &errorTransformer{err: innerErr},
		},
	)

	ctx := context.Background()

	// TransformFromStorage
	_, _, err := p.TransformFromStorage(ctx, []byte("enc:ciphertext"), nil)
	if err == nil {
		t.Errorf("expected error from TransformFromStorage, got nil")
	}

	// TransformToStorage
	_, err = p.TransformToStorage(ctx, []byte("plaintext"), nil)
	if err == nil {
		t.Errorf("expected error from TransformToStorage, got nil")
	}
}

// TestPrefixTransformerIdentityPrefixSkipsOnError verifies that an identity (empty) prefix
// transformer that returns an error is skipped, allowing subsequent transformers to match.
func TestPrefixTransformerIdentityPrefixSkipsOnError(t *testing.T) {
	decryptErr := fmt.Errorf("not encrypted data")
	fallbackResult := []byte("fallback-decrypted")

	p := NewPrefixTransformers(fmt.Errorf("no match"),
		// identity transformer that errors — simulates detecting the data is NOT in plaintext
		PrefixTransformer{Prefix: []byte{}, Transformer: &errorTransformer{err: decryptErr}},
		// real transformer with a prefix
		PrefixTransformer{Prefix: []byte("enc:"), Transformer: &testTransformer{from: fallbackResult}},
	)

	ctx := context.Background()
	out, _, err := p.TransformFromStorage(ctx, []byte("enc:ciphertext"), nil)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if !bytes.Equal(out, fallbackResult) {
		t.Errorf("got %q, want %q", out, fallbackResult)
	}
}

// TestPrefixTransformerCustomDefaultError verifies that a nil error passed to
// NewPrefixTransformers still produces a non-nil error on mismatch.
func TestPrefixTransformerCustomDefaultError(t *testing.T) {
	// Passing nil should use a default error message (not panic).
	p := NewPrefixTransformers(nil,
		PrefixTransformer{Prefix: []byte("x:"), Transformer: &identityTransformer{}},
	)

	ctx := context.Background()
	_, _, err := p.TransformFromStorage(ctx, []byte("y:data"), nil)
	if err == nil {
		t.Errorf("expected a non-nil error for unmatched prefix")
	}
}

// TestPrefixTransformerEmptyData verifies behaviour when transforming empty byte slices.
func TestPrefixTransformerEmptyData(t *testing.T) {
	p := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("p:"), Transformer: &identityTransformer{}},
	)
	ctx := context.Background()

	// Empty data has no matching prefix — should return the fallback error.
	_, _, err := p.TransformFromStorage(ctx, []byte{}, nil)
	if err == nil {
		t.Errorf("expected error for empty data with no matching prefix")
	}

	// TransformToStorage with empty data should succeed and produce just the prefix.
	p2 := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("p:"), Transformer: &identityTransformer{}},
	)
	got, err := p2.TransformToStorage(ctx, []byte{}, nil)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if !bytes.Equal(got, []byte("p:")) {
		t.Errorf("got %q, want %q", got, "p:")
	}
}

// TestPrefixTransformerOverlappingPrefixes verifies that when multiple transformers share
// a prefix, a failure in the first one allows the second to be tried.
func TestPrefixTransformerOverlappingPrefixes(t *testing.T) {
	expected := []byte("decrypted-by-second")
	p := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{
			Prefix:      []byte("k8s:enc:aes:"),
			Transformer: &errorTransformer{err: fmt.Errorf("wrong key")},
		},
		PrefixTransformer{
			Prefix:      []byte("k8s:enc:aes:"),
			Transformer: &testTransformer{from: expected},
		},
	)

	ctx := context.Background()
	out, stale, err := p.TransformFromStorage(ctx, []byte("k8s:enc:aes:ciphertext"), nil)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if !stale {
		t.Errorf("expected stale=true because match was not the first transformer")
	}
	if !bytes.Equal(out, expected) {
		t.Errorf("got %q, want %q", out, expected)
	}
}
